#include <stdio.h>
#include <stdbool.h>

int N;
int A[1000], B[1000], C[1000];
bool used[1000];

bool isValid(int col, int color) {
    for (int i = 0; i < col; i++) {
        if (C[i] == color) return false;
    }
    if (A[col] == color || B[col] == color) return false;
    return true;
}

bool backtrack(int col) {
    if (col == N) return true;
    for (int color = 1; color <= N; color++) {
        if (used[color]) continue;
        if (isValid(col, color)) {
            C[col] = color;
            used[color] = true;
            if (backtrack(col + 1)) return true;
            used[color] = false;
        }
    }
    return false;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) scanf("%d", &A[i]);
        for (int i = 0; i < N; i++) scanf("%d", &B[i]);
        int count = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) used[j] = false;
            C[0] = i;
            used[i] = true;
            if (backtrack(1)) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

