        for (int i = 0; i < col; i++) {
            if (C[i] == color) return false;
        }
        if (A[col] == color || B[col] == color) return false;
        return true;
    }

    public static boolean backtrack(int col) {
        if (col == N) return true;
        for (int color = 1; color <= N; color++) {
            if (used[color]) continue;
            if (isValid(col, color)) {
                C[col] = color;
                used[color] = true;
                if (backtrack(col + 1)) return true;
                used[color] = false;
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            N = sc.nextInt();
